// Convertir el array de usuarios en items separados (uno por usuario)
const data = $input.first().json;
if (!data.usuarios || data.usuarios.length === 0) {
  return [];
}
return data.usuarios.map(u => ({ json: u }));

// Verificar que la geocodificación tuvo resultado
const geo = $input.first().json;
if (!geo.results || geo.results.length === 0) {
  // Ciudad no encontrada: saltar este usuario
  return [];
}
const loc = geo.results[0];
return [{
  json: {
    lat: loc.latitude,
    lon: loc.longitude,
    city_resolved: `${loc.name}, ${loc.country_code || loc.country || ''}`
  }
}];

// Evaluar umbrales climáticos por sector y preparar datos para el AI Agent
const usuario = $('Filtrar por Hora').item.json;
const geo     = $('Verificar Geocodificacion').item.json;
const fc      = $input.first().json;  // forecast

const sectores = (usuario.sectores || 'agro').split(',').map(s => s.trim().toLowerCase());
const alertas  = [];
const current  = fc.current  || {};
const daily    = fc.daily    || {};
const hourly   = fc.hourly   || {};

// --- Valores clave del pronóstico ---
const tempMin3d   = daily.temperature_2m_min?.length ? Math.min(...daily.temperature_2m_min) : 99;
const tempMax3d   = daily.temperature_2m_max?.length ? Math.max(...daily.temperature_2m_max) : 0;
const lluviaMax   = daily.precipitation_sum?.length  ? Math.max(...daily.precipitation_sum)  : 0;
const vientoMax3d = daily.wind_speed_10m_max?.length ? Math.max(...daily.wind_speed_10m_max) : 0;
const vientoActual  = current.wind_speed_10m  || 0;
const rafagaActual  = current.wind_gusts_10m  || 0;
const visibilidad   = current.visibility      || 99999;
const capePico      = hourly.cape?.length    ? Math.max(...hourly.cape.slice(0, 48))                        : 0;
const radMedia      = hourly.shortwave_radiation?.length
  ? hourly.shortwave_radiation.slice(0, 24).reduce((a, b) => a + b, 0) / 24
  : 200;

// --- Umbrales por sector ---
if (sectores.includes('agro')) {
  if (tempMin3d <= 2)   alertas.push(`🥶 HELADA: mínima de ${tempMin3d.toFixed(1)}°C en los próximos 3 días`);
  if (lluviaMax >= 30)  alertas.push(`🌧️ LLUVIA INTENSA: ${lluviaMax.toFixed(0)} mm máx pronosticados`);
  if (vientoMax3d >= 60) alertas.push(`💨 VIENTO FUERTE: ráfagas de hasta ${vientoMax3d.toFixed(0)} km/h`);
}

if (sectores.includes('naval')) {
  if (vientoActual > 40)  alertas.push(`⚓ VIENTO PELIGROSO: ${vientoActual.toFixed(0)} km/h — operaciones en riesgo`);
  if (visibilidad < 1000) alertas.push(`🌫️ NIEBLA ESPESA: visibilidad ${Math.round(visibilidad)} m`);
  if (lluviaMax >= 20 && rafagaActual > 35)
    alertas.push(`🌊 MAL TIEMPO COMBINADO: lluvia + ráfagas de ${rafagaActual.toFixed(0)} km/h`);
}

if (sectores.includes('aereo')) {
  if (capePico > 1500)    alertas.push(`⚡ ALTA INESTABILIDAD: CAPE ${Math.round(capePico)} J/kg — tormentas posibles`);
  if (vientoActual > 60)  alertas.push(`✈️ VIENTOS INTENSOS: ${vientoActual.toFixed(0)} km/h en superficie`);
  if (visibilidad < 3000) alertas.push(`🌫️ VISIBILIDAD REDUCIDA: ${(visibilidad / 1000).toFixed(1)} km`);
}

if (sectores.includes('energia')) {
  if (radMedia < 50)       alertas.push(`☁️ BAJA RADIACIÓN SOLAR: ${radMedia.toFixed(0)} W/m² promedio — impacto en paneles`);
  if (vientoMax3d > 80)    alertas.push(`🌀 VIENTO EXTREMO: ${vientoMax3d.toFixed(0)} km/h — revisar turbinas eólicas`);
}

return [{
  json: {
    ...usuario,
    alertas,
    nivel: alertas.length > 0 ? 'alerta' : 'normal',
    alertas_texto: alertas.length > 0 ? alertas.join('\n') : 'Sin condiciones críticas hoy.',
    ubicacion_resuelta: geo.city_resolved || usuario.ubicacion_nombre,
    clima_resumen: {
      temp_actual:  current.temperature_2m,
      temp_min_3d:  tempMin3d,
      temp_max_3d:  tempMax3d,
      lluvia_max_3d: lluviaMax,
      viento_actual: vientoActual,
      rafaga_actual: rafagaActual,
      humedad:      current.relative_humidity_2m,
    }
  }
}];

